proof fn phi_2_lemma_write_seq_push_external_body(mem: PTMem, writes: Seq<(usize, usize)>, addr: usize, value: usize)
    ensures
        mem.write_seq(writes.push((addr, value)))
            == (PTMem {
                pml4: mem.pml4,
                mem: mem.write_seq(writes).mem.insert(addr, value),
            }),
{
    mem.lemma_write_seq_push(writes, addr, value);
}

