        pre.wf(c),
        pre.inv_sbuf_facts(c),
        step_WriteNonneg(pre, post, c, lbl) || step_WriteNonpos(pre, post, c, lbl),
        lbl->Write_0 != pre.writes.core,
    ensures
        pre.writer_sbuf() =~= seq![],
{
    assert(pre.writes.tso.contains(pre.writer_sbuf()[0].0)) by {
        // If sbuf non-empty, tso must be non-empty, but step requires either tso empty or same core
    };
}
